INSERT OR IGNORE INTO chapter (id,tier,chapter_no,title,description,`order`,status,createdAt,updatedAt) VALUES ('22-empire-os',3,22,'EMPIRE OS','He dieu hanh Dental Empire OS',22,'draft','2026-06-20T15:30:58Z','2026-06-20T15:30:58Z');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('38737dd6-0c82-4684-a2fb-ea6b2fcdffea','22-empire-os',NULL,1,'T3A - CHƯƠNG 22: Dental OS Module Map','t3a-chuong-22-dental-os-module-map',0,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b658346b-f55b-4f07-bc1b-fdde0df7b3c5','38737dd6-0c82-4684-a2fb-ea6b2fcdffea',0,'text','Chúng ta đã cùng nhau đi qua hai tầng kiến trúc đồ sộ của **Dental Empire OS**. Tại Tầng 1 và Tầng 2, chúng ta đã kiến tạo xong bộ gen định vị, lắp đặt cỗ máy Media Network, khơi thông dòng thác khách giới thiệu (Referral) và xây dựng pháo đài cộng đồng (Patient Community) bất khả xâm phạm. Đó là những tầng giúp phòng khám của bạn xác lập tư duy chiến lược sắc bén về mặt lý thuyết quản trị và cấu trúc dòng tiền hữu cơ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4b58e9a9-7d6b-46d5-b649-201bb74effd8','38737dd6-0c82-4684-a2fb-ea6b2fcdffea',1,'text','Tuy nhiên, có một sự thật tàn nhẫn trên mặt đất vận hành: **Bệnh nhân không xuống tiền vì một chiến lược hay trên giấy, bộ máy phòng khám không tự chạy vì một tầm nhìn vĩ đại của người sáng lập.**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a388b4b7-6c3f-4a73-819d-0f174dd34c1f','38737dd6-0c82-4684-a2fb-ea6b2fcdffea',2,'text','Nếu không có tầng công cụ thực thi, những SOP tiếp đón 5 sao sẽ lập tức bị gãy ngay khi phòng khám quá tải; những kịch bản Recall tự động sẽ bị nhân sự bỏ quên vì mệt mỏi; và năng lực y khoa của Bác sĩ sẽ bị kéo lùi bởi sự cẩu thả của đội ngũ trợ thủ, lễ tân tuyến đầu.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b1d4c39b-3aa2-4e07-acab-4c7e56cc6d29','38737dd6-0c82-4684-a2fb-ea6b2fcdffea',3,'text','Chào mừng anh bước vào **Tầng 3: Hệ điều hành thực thi (How)**. Đây là nơi chúng ta cởi bỏ chiếc áo vest chiến lược để xắn tay áo bước vào chiến trường thực địa. Tầng 3 là câu trả lời đanh thép cho câu hỏi: *Làm thế nào để bộ máy nha khoa tự vận hành chuẩn xác đến từng milimet mà không cần sự hiện diện 24/7 của chủ phòng khám?*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a760c0cc-6263-4d98-b4d5-12a33222ef89','38737dd6-0c82-4684-a2fb-ea6b2fcdffea',4,'image',NULL,'book/22-empire-os/bbe6940c-78a9-4c9a-95bd-4bd2bb204d3c-img01.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c6d634da-937d-4978-b33b-8839efe84d00','38737dd6-0c82-4684-a2fb-ea6b2fcdffea',5,'text','**Kiến trúc thượng tầng và bản đồ ánh xạ hệ điều hành quản trị**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('ab93e795-f6ce-4b18-9ee3-46aa3863125a','22-empire-os','38737dd6-0c82-4684-a2fb-ea6b2fcdffea',2,'22.1 Executive Summary &amp; Tư duy cốt lõi:','221-executive-summary-amp-tu-duy-cot-loi',1,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d78fea23-8d75-4bcf-a6b0-26828cc263cf','ab93e795-f6ce-4b18-9ee3-46aa3863125a',6,'text','**Dịch chuyển từ chiến lược sang mã lệnh vận hành**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4879959c-b34a-4849-934f-8ed14761b5ef','ab93e795-f6ce-4b18-9ee3-46aa3863125a',7,'text','Nếu bản đồ **Dental Empire Master Map** được ví như một bản vẽ kiến trúc hoàn chỉnh trả lời cho câu hỏi: *"Phòng khám RHM cần xây dựng hệ sinh thái tăng trưởng như thế nào?"*, thì **Dental OS Module Map** chính là sơ đồ mạch điện và hệ lệnh kỹ thuật trả lời cho câu hỏi: *"Ai vận hành từng phần? Quy trình là gì? KPI là gì? Dữ liệu nằm ở đâu? Và kiểm soát bằng cách nào?"*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a4d3722c-6fc4-4710-80c0-cc6c63765ac8','ab93e795-f6ce-4b18-9ee3-46aa3863125a',8,'text','Một sai lầm chí mạng của các nhà điều hành nha khoa truyền thống là để lại các ý tưởng chiến lược nằm trên giấy hoặc trong các buổi họp định hướng mơ hồ. Nhân sự sàn vận hành không thể thực thi nếu chỉ nhận được những mệnh lệnh chung chung như "hãy tăng trải nghiệm khách hàng" hoặc "hãy kéo thêm nhiều khách giới thiệu". Hệ điều hành đòi hỏi sự rõ ràng tuyệt đối về mặt toán học quản trị.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('eb4eb418-cee6-483b-8836-cffa3a94a510','ab93e795-f6ce-4b18-9ee3-46aa3863125a',9,'text','**Dental OS Module Map** đóng vai trò là trục ánh xạ thượng tầng, bóc tách toàn bộ 10 lớp giá trị cốt lõi của mô hình Dental Empire thành **9 phân hệ quản trị số hóa (9 Modules)**. Sự giao thoa này giúp phòng khám làm chủ toàn bộ dòng chảy dữ liệu, phân định trách nhiệm không chồng chéo và thiết lập các Dashboard kiểm soát thời gian thực hằng ngày.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('b42cd6b0-760d-4daf-850a-18a0f2290a84','22-empire-os','38737dd6-0c82-4684-a2fb-ea6b2fcdffea',2,'22.2 Ma trận ánh xạ: chuyển hóa lớp giá trị thành phân hệ quản trị','222-ma-tran-anh-xa-chuyen-hoa-lop-gia-tri-thanh-phan-he-quan-tri',2,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('38776c91-97de-4cc8-8341-817fbdaa0a5c','b42cd6b0-760d-4daf-850a-18a0f2290a84',10,'text','Để có cái nhìn scannable toàn diện, nhà quản trị sử dụng bảng ma trận dưới đây để định vị chính xác phân hệ nào chịu trách nhiệm cho lớp tài sản nào trong hệ thống:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('cde540c3-718e-42d7-a472-57deb1a9c363','b42cd6b0-760d-4daf-850a-18a0f2290a84',11,'image',NULL,'book/22-empire-os/58138c31-da4e-4ca9-98eb-a6b67e42251b-img02.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('416b7837-65d3-4004-b095-b6a87dbd9653','22-empire-os','38737dd6-0c82-4684-a2fb-ea6b2fcdffea',2,'22.3 Giải mã thực địa 9 phân hệ quản trị của Dental OS','223-giai-ma-thuc-ia-9-phan-he-quan-tri-cua-dental-os',3,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5e97c6f7-13d8-45ee-9de4-fe0538aa78e2','416b7837-65d3-4004-b095-b6a87dbd9653',12,'text','Để biến phòng khám thành một bộ máy tự chạy chuẩn xác, 9 phân hệ quản trị được cấu hình chi tiết về mặt nhân sự, quy trình, dữ liệu và kiểm soát như sau:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('c6a0fabe-0e0d-47fc-81e7-915b33a22cf4','22-empire-os','416b7837-65d3-4004-b095-b6a87dbd9653',3,'Strategy OS (Hệ điều hành Chiến lược)Người phụ trách chính: Chủ sở hữu / Hội đồng quản trị phòng khám.Quy trình cốt lõi: Thiết lập mục tiêu OKRs hằng năm; thẩm định và phê duyệt ngân sách tổng; hoạch định chiến lược mở rộng chuỗi hoặc nhượng quyền thương hiệu.KPI đo lường: Tốc độ tăng trưởng doanh thu ròng (MoM/YoY); Chỉ số hoàn vốn đầu tư chiến lược (ROI).Nơi lưu trữ dữ liệu: Master Executive Dashboard.Cơ chế kiểm soát: Họp hội đồng chiến lược định kỳ hằng quý để căn chỉnh bánh đà.','strategy-os-he-ieu-hanh-chien-luocnguoi-phu-trach-chinh-chu-so-huu-hoi-ong-quan-',4,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('21f08c80-04a9-4bcb-8b70-838e7473905e','22-empire-os','416b7837-65d3-4004-b095-b6a87dbd9653',3,'Marketing OS (Hệ điều hành Tiếp thị)Người phụ trách chính: Trưởng phòng Marketing (CMO / Marketing Manager).Quy trình cốt lõi: Quản trị thương hiệu cá nhân của Bác sĩ sáng lập; vận hành đa kênh trên mạng xã hội; sản xuất kho nội dung vụn hóa; lập lịch giáo dục thường thức (Patient Education Calendar).KPI đo lường: Chi phí sắm khách hàng (CAC); Sản lượng lead nóng chất lượng cao hằng tháng; Chỉ số tương tác (Engagement Rate) trên các nền tảng xã hội.Nơi lưu trữ dữ liệu: Facebook/TikTok Ads Manager, Google Analytics, Central Content Library.Cơ chế kiểm soát: Duyệt lịch biên tập nội dung số hằng tuần; đối soát chi phí quảng cáo theo ngày.','marketing-os-he-ieu-hanh-tiep-thinguoi-phu-trach-chinh-truong-phong-marketing-cm',5,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('89889581-bdbe-48c2-80c0-8120400c4ac9','22-empire-os','416b7837-65d3-4004-b095-b6a87dbd9653',3,'Sales OS (Hệ điều hành Quy trình Chuyển đổi)Người phụ trách chính: Trưởng bộ phận Tư vấn / Chuyên viên tư vấn chính.Quy trình cốt lõi: Tiếp nhận lead nóng từ Marketing OS; phân loại khách hàng trên phễu; thực thi kịch bản tư vấn phác đồ và xử lý từ chối tại phòng VIP.KPI đo lường: Tỷ lệ chốt phác đồ tại ghế nha (Case Acceptance Rate); Giá trị đơn hàng trung bình trên mỗi ca lâm sàng; Doanh thu trung bình theo giờ của từng ghế điều trị.Nơi lưu trữ dữ liệu: CRM Sales Pipeline Tracker.Cơ chế kiểm soát: Thống kê tỷ lệ rơi rụng lead hằng tuần; nghe lại ghi âm cuộc gọi tư vấn mẫu để tối ưu kịch bản.','sales-os-he-ieu-hanh-quy-trinh-chuyen-oinguoi-phu-trach-chinh-truong-bo-phan-tu-',6,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('b02b110b-5b5b-455b-a85d-4d89b34d26b5','22-empire-os','416b7837-65d3-4004-b095-b6a87dbd9653',3,'Clinic OS (Hệ điều hành Lâm sàng &amp; Vô trùng)Người phụ trách chính: Giám đốc chuyên môn / Bác sĩ trưởng ca.Quy trình cốt lõi: Tiếp nhận bệnh nhân từ Sales OS; thực thi phác đồ điều trị lâm sàng; kiểm soát quy trình vô trùng khép kín; ký duyệt nghiệm thu và bàn giao bộ ảnh Before/After cho hệ thống dữ liệu.KPI đo lường: Tỷ lệ lỗi biến chứng y khoa (bằng 0%); Thời gian lãng phí trống ghế nha; Điểm số hài lòng điều trị của bệnh nhân.Nơi lưu trữ dữ liệu: Hệ thống hồ sơ bệnh án điện tử (EMR).Cơ chế kiểm soát: Bắt buộc thực hiện Checklist vô trùng và bảo dưỡng thiết bị hằng ngày; audit ngẫu nhiên hồ sơ bệnh án điện tử hằng tuần.','clinic-os-he-ieu-hanh-lam-sang-amp-vo-trungnguoi-phu-trach-chinh-giam-oc-chuyen-',7,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('34639cb4-b8e7-4ee4-9662-ac0dd688d5ec','22-empire-os','416b7837-65d3-4004-b095-b6a87dbd9653',3,'Patient OS (Hệ điều hành Quản trị Vòng đời Bệnh nhân)Người phụ trách chính: Trưởng bộ phận Chăm sóc khách hàng (Patient Care Owner).Quy trình cốt lõi: Tiếp nhận dữ liệu hậu phẫu từ Clinic OS; kích hoạt luồng nhắc lịch tự động (Automated Recall Flow); thực thi kịch bản phá băng tệp khách cũ ngủ đông (Reactivation Flow); vận hành các tiểu cộng đồng.KPI đo lường: Tỷ lệ hoàn thành lịch nhắc khám định kỳ (Recall Completion Rate); Tỷ lệ rời bỏ hệ thống (Churn Rate); Chỉ số đo lường mức độ thiện cảm khách hàng (NPS).Nơi lưu trữ dữ liệu: CRM Patient Lifecycle Module, Hệ thống Zalo OA tích hợp.Cơ chế kiểm soát: Giám sát thời gian phản hồi tin nhắn của nhân sự; đối soát tỷ lệ cuộc hẹn Recall thành công hằng tuần.','patient-os-he-ieu-hanh-quan-tri-vong-oi-benh-nhannguoi-phu-trach-chinh-truong-bo',8,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('4b8d730a-24b9-4460-8d15-c58b96b89f35','22-empire-os','416b7837-65d3-4004-b095-b6a87dbd9653',3,'Referral OS (Hệ sinh thái Lan tỏa)Người phụ trách chính: Trưởng bộ phận Phát triển Cộng đồng (Referral Owner).Quy trình cốt lõi: Xác định các điểm chạm cảm xúc đỉnh cao của bệnh nhân; kích hoạt các chương trình tri ân tặng thẻ đặc quyền cho người thân hội viên VIP; số hóa tài sản tri thức có thể chia sẻ (Shareable Assets).KPI đo lường: Tỷ lệ chuyển đổi từ lời giới thiệu thành ca lâm sàng mới; Tổng số doanh thu hữu cơ sản sinh từ nguồn Referral.Nơi lưu trữ dữ liệu: Mã định danh Referral (Referral Tag Link) trên CRM hệ thống.Cơ chế kiểm soát: Đối soát danh sách quà tặng tri ân hằng tháng; kiểm tra tính xác thực của nguồn lead giới thiệu.','referral-os-he-sinh-thai-lan-toanguoi-phu-trach-chinh-truong-bo-phan-phat-trien-',9,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('40ca3536-29de-4bd9-a86e-632c0c0b083f','22-empire-os','416b7837-65d3-4004-b095-b6a87dbd9653',3,'Finance OS (Hệ điều hành Quản trị Tài chính)Người phụ trách chính: Kế toán trưởng / CFO phòng khám.Quy trình cốt lõi: Quản trị dòng tiền mặt thu trước từ các gói Membership và kế hoạch thanh toán trả góp; kiểm soát chi phí vận hành cố định; hạch toán biên lợi nhuận thuần trên từng phân khúc dịch vụ can thiệp sâu.KPI đo lường: Dòng tiền mặt trả trước (Upfront Cashflow); Biên lợi nhuận thuần trên doanh thu ròng; Tỷ lệ chi phí vận hành trên tổng doanh thu.Nơi lưu trữ dữ liệu: Phần mềm quản trị tài chính doanh nghiệp Fynlo.Cơ chế kiểm soát: Xuất báo cáo dòng tiền đối soát hằng tuần; kiểm duyệt mọi yêu cầu chi phí vượt định mức.','finance-os-he-ieu-hanh-quan-tri-tai-chinhnguoi-phu-trach-chinh-ke-toan-truong-cf',10,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('9bbceaa2-f829-418f-8dc9-b95eacff7721','22-empire-os','416b7837-65d3-4004-b095-b6a87dbd9653',3,'People OS (Hệ điều hành Nhân sự &amp; Động lực nội sinh)Người phụ trách chính: Trưởng phòng Nhân sự (HR Manager).Quy trình cốt lõi: Tuyển dụng nhân sự theo role card; onboarding nhân viên mới; tổ chức các chương trình đào tạo Role-play thực địa; vận hành mô hình tính lương thưởng tự động hóa dựa trên Khung năng lực vị trí.KPI đo lường: Chỉ số hiệu suất làm việc của nhân sự hằng tháng; Tỷ lệ nhân sự vượt qua bài kiểm tra năng lực sàn; Tỷ lệ nghỉ việc nội bộ (Turnover Rate).Nơi lưu trữ dữ liệu: Phần mềm theo dõi attendance Desklog, Hệ thống Master Competency Framework Sheet.Cơ chế kiểm soát: Đánh giá khung năng lực và chấm điểm KPI định kỳ hằng tháng; rà soát biên bản vi phạm kỷ luật sàn.','people-os-he-ieu-hanh-nhan-su-amp-ong-luc-noi-sinhnguoi-phu-trach-chinh-truong-p',11,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('1feaf271-e543-4e55-b809-e0e1ec1fbef1','22-empire-os','416b7837-65d3-4004-b095-b6a87dbd9653',3,'Data OS (Hệ điều hành Hạ tầng và Liên kết Dữ liệu)Người phụ trách chính: Giám đốc công nghệ / Chuyên viên phân tích dữ liệu (CTO / Data Analyst).Quy trình cốt lõi: Xây dựng hạ tầng cơ sở dữ liệu; liên kết API giữa các phân hệ quản trị; bảo mật thông tin hồ sơ y khoa; cấu hình và đồng bộ hóa các Dashboard hiển thị thời gian thực cho Ban giám đốc.KPI đo lường: Độ chính xác và đồng bộ của dữ liệu giữa các phân hệ (đạt 100%); Thời gian uptime của hệ thống hạ tầng số; Tốc độ truy xuất báo cáo của nhà quản trị.Nơi lưu trữ dữ liệu: Hạ tầng dữ liệu tập trung (Cấu hình qua Supabase / Vercel / Central Database System).Cơ chế kiểm soát: Audit hệ thống bảo mật định kỳ hằng tháng; phân quyền truy cập thông tin nghiêm ngặt theo phân tầng chức vụ.','data-os-he-ieu-hanh-ha-tang-va-lien-ket-du-lieunguoi-phu-trach-chinh-giam-oc-con',12,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('798cb396-738c-4cfc-9a54-833b20500800','1feaf271-e543-4e55-b809-e0e1ec1fbef1',13,'text','**Mantra tối thượng của Bản đồ quản trị:***"Một phòng khám nha khoa xuất sắc không được vận hành bằng cảm xúc cá nhân của người chủ, mà được điều khiển bằng một hệ thống phân hệ đồng bộ, nơi dữ liệu tự động chảy, quy trình tự động chạy, và con người thực thi theo kỷ luật của mã lệnh."*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('bd345f57-6c11-4d6c-bc53-39b6f4cd59a5','22-empire-os','38737dd6-0c82-4684-a2fb-ea6b2fcdffea',2,'22.4 Sơ đồ đường ống đồng bộ: một vòng quay của hồ sơ khách hàng qua 9 modules','224-so-o-uong-ong-ong-bo-mot-vong-quay-cua-ho-so-khach-hang-qua-9-modules',13,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('006c8c44-be97-4077-849b-5359edf667bf','bd345f57-6c11-4d6c-bc53-39b6f4cd59a5',14,'image',NULL,'book/22-empire-os/aa41688e-0d69-4e16-9b8f-c78ca14fa8e1-img03.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('332d3ad8-fc4f-4d94-be46-5f46dfac1fd7','22-empire-os','38737dd6-0c82-4684-a2fb-ea6b2fcdffea',2,'22.5 Bảy mục tiêu chiến lược của Dental OS Module Map - Khung phương châm thực thi toàn diện','225-bay-muc-tieu-chien-luoc-cua-dental-os-module-map-khung-phuong-cham-thuc-thi-',14,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('15fb2fda-0729-4492-bb2f-c78345b66eed','332d3ad8-fc4f-4d94-be46-5f46dfac1fd7',15,'text','Nếu như **Dental Empire** đóng vai trò là một "bản đồ kho báu" định vị toàn bộ các mỏ neo tăng trưởng, thì **Dental OS Module Map** chính là bản hướng dẫn chế tạo và vận hành cỗ máy khai thác hằng ngày. Ý đồ kiến trúc thượng tầng này không sinh ra để làm đẹp hồ sơ quản trị, mà hướng tới việc giải quyết triệt để 7 mục tiêu thực chiến cốt lõi dưới đây, biến phòng khám RHM thành một thực thể kinh doanh số hóa, kỷ luật và tự chủ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('660a3cb9-0394-4bc4-a87b-16f2b5bd9166','22-empire-os','332d3ad8-fc4f-4d94-be46-5f46dfac1fd7',3,'BIẾN CHIẾN LƯỢC THÀNH VẬN HÀNH (FROM BLUEPRINT TO GROUND WORK)','bien-chien-luoc-thanh-van-hanh-from-blueprint-to-ground-work',15,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('46ceabd9-5c0d-4d84-8b92-a1288821e394','660a3cb9-0394-4bc4-a87b-16f2b5bd9166',16,'text','Chiến lược dù vĩ đại đến đâu cũng sẽ trở nên vô nghĩa nếu đội ngũ nhân sự tuyến đầu không biết phải làm gì vào lúc 8 giờ sáng mỗi ngày.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('00c51433-a572-4a98-85bc-6348ac96597a','660a3cb9-0394-4bc4-a87b-16f2b5bd9166',17,'text','- **Thực thi:** *Dental OS* bóc tách các tầng trừu tượng như "Trải nghiệm khách hàng" hay "Hệ sinh thái lan tỏa" thành các tác vụ vật lý chạy ngầm hằng ngày.- **Kết quả:** Biến các khái niệm lý thuyết thành hành động cụ thể trên sàn vận hành. Mỗi cú click chuột của lễ tân, mỗi lời dặn hậu phẫu của trợ thủ đều được lập trình để khớp chính xác với bánh đà tăng trưởng chung của toàn bộ hệ thống.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('7616f6b7-65a8-46f8-bd73-a7de2d3e333c','22-empire-os','332d3ad8-fc4f-4d94-be46-5f46dfac1fd7',3,'GÁN RÕ TRÁCH NHIỆM (THE DEFINITIVE ACCOUNTABILITY MATRIX)','gan-ro-trach-nhiem-the-definitive-accountability-matrix',16,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d4c0050a-af88-4b85-8cde-c4a0b821b39e','7616f6b7-65a8-46f8-bd73-a7de2d3e333c',18,'text','Một trong những nguyên nhân khiến các phòng khám nha khoa bị gián đoạn vận hành là hội chứng "cha chung không ai khóc" hoặc chồng chéo quyền hạn giữa các phòng ban.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('33b3365d-ca75-47c7-840d-872a8744aecc','7616f6b7-65a8-46f8-bd73-a7de2d3e333c',19,'text','- **Thực thi:** Module Map gán đích danh một **Owner (Người chịu trách nhiệm chính)**, các **Contributors (Nhân sự phối hợp)** và bộ chỉ số hiệu suất riêng biệt cho từng lớp tài sản của hệ sinh thái.- **Kết quả:** Triệt tiêu hoàn toàn vùng xám trách nhiệm. Khi một chỉ số trên Dashboard sụt giảm, nhà quản trị biết chính xác phải đối thoại với ai, ở phân hệ nào, mà không cần phải tổ chức các buổi họp đổ lỗi tập thể.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('577cec8b-cc6b-46a0-a01d-bf97340593e4','22-empire-os','332d3ad8-fc4f-4d94-be46-5f46dfac1fd7',3,'CHUẨN HÓA QUY TRÌNH (PROCESS INSTITUTIONALIZATION)','chuan-hoa-quy-trinh-process-institutionalization',17,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('379a437a-b423-43b3-b155-e63020cf7777','577cec8b-cc6b-46a0-a01d-bf97340593e4',20,'text','Giải phóng phòng khám khỏi trạng thái vận hành bằng "tâm trạng" hoặc phụ thuộc vào thói quen ngẫu hứng của nhân sự.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8a5e141b-fea3-4991-ab90-7af42678181d','577cec8b-cc6b-46a0-a01d-bf97340593e4',21,'text','- **Thực thi:** Định hình và đóng gói cứng toàn bộ các tài sản vận hành cho từng Module OS bao gồm: Quy trình thao tác chuẩn (SOP), Bảng kiểm tra hành động (Checklist), Biểu mẫu số hóa (Templates) và Sơ đồ đường ống dữ liệu (Data Pipeline).- **Kết quả:** Tạo ra tính đồng nhất tuyệt đối về mặt chất lượng dịch vụ. Khách hàng dù đến khám vào ngày đầu tuần hay cuối tuần đều được tiếp đón và điều trị theo một tiêu chuẩn đồng bộ như nhau.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('67c86d5a-3d0b-4859-9a29-58d137b1aa0e','22-empire-os','332d3ad8-fc4f-4d94-be46-5f46dfac1fd7',3,'GẮN KPI VÀO TỪNG TẦNG (GRANULAR FUNNEL MICROMANAGEMENT)','gan-kpi-vao-tung-tang-granular-funnel-micromanagement',18,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a0768b3e-8bcd-446a-8299-1812029c087a','67c86d5a-3d0b-4859-9a29-58d137b1aa0e',22,'text','Nhà quản trị lỗi thời chỉ nhìn vào con số Doanh thu đích cuối (End Revenue) để đánh giá sức khỏe phòng khám. Khi doanh thu giảm, họ hoang mang không biết hệ thống bị lỗi ở bộ phận nào. *Dental OS* bẻ gãy trục doanh thu thành **9 Điểm rơi dữ liệu hình phễu (9 Conversion Drop-points)** được đo lường nghiêm ngặt hằng tuần:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('bd7e77c3-42cb-4392-a0cf-6041e3ac893d','67c86d5a-3d0b-4859-9a29-58d137b1aa0e',23,'image',NULL,'book/22-empire-os/faa3ec96-ac28-433d-afcb-a77ffd27693e-img04.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('11d9dd6d-1fa3-4835-b25e-8dcbd0840ac8','22-empire-os','332d3ad8-fc4f-4d94-be46-5f46dfac1fd7',3,'TẠO DASHBOARD QUẢN TRỊ (DATA-DRIVEN REALTIME MANAGEMENT)','tao-dashboard-quan-tri-data-driven-realtime-management',19,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('80d01027-52b9-4b32-933a-c1bc8da1d3e0','11d9dd6d-1fa3-4835-b25e-8dcbd0840ac8',24,'text','Cung cấp cho người sáng lập một "bảng điều khiển khoang lái" minh bạch, loại bỏ hoàn toàn các báo cáo cảm tính theo kiểu "em thấy tháng này khách đông".',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3c2657f1-b86e-450d-b87a-80650363e03c','11d9dd6d-1fa3-4835-b25e-8dcbd0840ac8',25,'text','- **Thực thi:** Đồng bộ hóa dữ liệu từ 9 module OS lên một Dashboard trung tâm thời gian thực.- **Kết quả:** Giúp Founder Bác sĩ Nguyễn Phước Vinh nhìn rõ vị trí nào trong hệ thống đang là "nút thắt cổ chai" (Bottleneck) kìm hãm dòng tiền. Nếu lead nhiều nhưng booking thấp ➔ Sửa Sales OS. Nếu booking cao nhưng show-up thấp ➔ Sửa kịch bản nhắc lịch của Patient OS.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('36a2c342-bfa2-41d3-81b8-8802b72c3b14','22-empire-os','332d3ad8-fc4f-4d94-be46-5f46dfac1fd7',3,'TẠO NỀN CHO ĐÀO TẠO ĐỘI NGŨ (DECENTRALIZED BRAIN PLATFORM)','tao-nen-cho-ao-tao-oi-ngu-decentralized-brain-platform',20,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e678fba4-7ac2-4334-857a-daa952df3e89','36a2c342-bfa2-41d3-81b8-8802b72c3b14',26,'text','Triệt tiêu hội chứng rò rỉ tri thức khi có sự biến động về mặt nhân sự và rút ngắn thời gian Onboarding cho người mới.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9517288c-6ff3-4201-864a-6a012e1b4030','36a2c342-bfa2-41d3-81b8-8802b72c3b14',27,'text','- **Thực thi:** Biến hệ điều hành *Dental OS* thành một cuốn bách khoa toàn thư nội bộ chuẩn hóa.- **Kết quả:** Nhân sự mới (lễ tân, phụ tá, CSKH) khi gia nhập phòng khám không cần phải tự bơi hay phụ thuộc vào tâm trạng dắt mối của người cũ. Họ được nhúng trực tiếp vào hệ thống tài liệu đào tạo Role-play và Checklist thực hành tự thân, giúp đạt 90\\% năng suất sàn chỉ trong vòng 14 ngày đầu tiên.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('6a24112a-1dd3-4a23-b796-a78ee503698b','22-empire-os','332d3ad8-fc4f-4d94-be46-5f46dfac1fd7',3,'TẠO KHẢ NĂNG SCALE (THE INFINITE SCALABILITY GRID)','tao-kha-nang-scale-the-infinite-scalability-grid',21,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('aa9ebe5c-37c6-43d2-81fa-98a7592befe4','6a24112a-1dd3-4a23-b796-a78ee503698b',28,'text','Mô hình nha khoa truyền thống không thể mở rộng vì mọi việc lớn nhỏ đều phải đi qua bộ não và sự kiểm duyệt trực tiếp của chủ phòng khám. Khi chủ phòng khám rời đi, bộ máy lập tức rơi vào trạng thái tê liệt.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7789bfc0-5e74-402d-96ca-caca9104ffc2','6a24112a-1dd3-4a23-b796-a78ee503698b',29,'text','- **Thực thi:** Module Map đóng gói toàn bộ phòng khám thành một **Mã nguồn vận hành chuẩn (Core Source Code)**.- **Kết quả:** Tạo lập khả năng nhân bản quy mô lớn (Scale-up). Khi một cơ sở tại Hà Nội đã chạy mượt mà trên hạ tầng 9 Module OS, nhà sáng lập hoàn toàn có thể mang nguyên bản mã lệnh này để cắm sạc (Plug-and-Play) cho cơ sở tiếp theo tại TP. Hồ Chí Minh, hoặc dễ dàng mở rộng thêm các dòng sản phẩm Homecare, dịch vụ mới hay nhượng quyề',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d8d40f36-4815-401b-ba9b-bf37a7505f88','6a24112a-1dd3-4a23-b796-a78ee503698b',30,'text','**Bản đúc kết điều hành:***"Dental OS Module Map ra đời để giải quyết một bài toán duy nhất: Biến phòng khám từ một thực thể sống phụ thuộc vào con người thành một hệ sinh thái vận hành phụ thuộc vào hệ thống. Khi 7 mục tiêu này được nghiệm thu hoàn tất, phòng khám của bạn đã chính thức sở hữu một hạ tầng quản trị đạt tiêu chuẩn quốc tế, sẵn sàng cho những mục tiêu bùng nổ quy mô vĩ mô."*',NULL,NULL,NULL,NULL,NULL);
